import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { doctorAPI } from '../services/api';
import { 
  FaSearch, 
  FaFilter, 
  FaStar, 
  FaStarHalfAlt, 
  FaRegStar, 
  FaVideo, 
  FaCalendar,
  FaUserMd,
  FaMapMarkerAlt,
  FaLanguage,
  FaClock,
  FaMicrophone,
  FaTimes,
  FaPhoneSlash,
  FaVolumeUp,
  FaVideoSlash,
  FaMicrophoneSlash,
  FaComment,
  FaExpand,
  FaCompress
} from 'react-icons/fa';

// Call UI Component
const CallUI = ({ callType, doctor, onEndCall }) => {
  const [callDuration, setCallDuration] = useState(0);
  const [isMuted, setIsMuted] = useState(false);
  const [isCameraOn, setIsCameraOn] = useState(callType === 'video');
  const [isMinimized, setIsMinimized] = useState(false);
  const [isSpeakerOn, setIsSpeakerOn] = useState(true);
  const [showChat, setShowChat] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => {
      setCallDuration(prev => prev + 1);
    }, 1000);

    return () => clearInterval(timer);
  }, []);

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-95 flex items-center justify-center z-50">
      <div className={`bg-gray-900 rounded-xl shadow-2xl overflow-hidden ${isMinimized ? 'w-80 h-60' : 'w-full max-w-6xl h-full max-h-screen'} transition-all duration-300`}>
        {/* Header */}
        <div className="bg-gray-800 p-4 flex items-center justify-between">
          <div className="text-white">
            <h3 className="font-semibold text-lg">{callType === 'video' ? 'Video Call' : 'Audio Call'} with {doctor?.name}</h3>
            <p className="text-gray-300 text-sm">{doctor?.specialty}</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="bg-red-500 text-white px-3 py-1 rounded-full text-sm font-mono">
              {formatTime(callDuration)}
            </div>
            <button
              onClick={() => setIsMinimized(!isMinimized)}
              className="text-gray-400 hover:text-white p-2 hover:bg-gray-700 rounded-lg transition-colors"
              title={isMinimized ? "Maximize" : "Minimize"}
            >
              {isMinimized ? <FaExpand /> : <FaCompress />}
            </button>
          </div>
        </div>

        {/* Call Content */}
        <div className={`${isMinimized ? 'h-32' : 'flex-1 min-h-96'} flex items-center justify-center bg-gray-800 relative`}>
          {callType === 'video' ? (
            <div className="relative w-full h-full">
              {isCameraOn ? (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 w-full h-full p-4">
                  {/* Doctor's video placeholder */}
                  <div className="bg-gradient-to-br from-blue-600 to-blue-800 rounded-xl flex flex-col items-center justify-center text-white relative overflow-hidden">
                    <div className="w-32 h-32 bg-blue-500 rounded-full flex items-center justify-center mb-4 border-4 border-white shadow-lg">
                      <span className="text-4xl font-bold">{doctor?.name?.charAt(0)}</span>
                    </div>
                    <p className="font-semibold text-xl">{doctor?.name}</p>
                    <p className="text-blue-200">{doctor?.specialty}</p>
                    <div className="absolute top-4 right-4 bg-green-500 w-4 h-4 rounded-full animate-pulse"></div>
                  </div>
                  {/* User's video placeholder */}
                  <div className="bg-gradient-to-br from-green-600 to-green-800 rounded-xl flex flex-col items-center justify-center text-white relative overflow-hidden">
                    <div className="w-32 h-32 bg-green-500 rounded-full flex items-center justify-center mb-4 border-4 border-white shadow-lg">
                      <span className="text-4xl font-bold">You</span>
                    </div>
                    <p className="font-semibold text-xl">You</p>
                    <p className="text-green-200">Patient</p>
                    <div className="absolute top-4 right-4 bg-green-400 w-4 h-4 rounded-full animate-pulse"></div>
                  </div>
                </div>
              ) : (
                <div className="text-white text-center">
                  <div className="w-40 h-40 bg-gray-600 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-gray-500">
                    <FaVideoSlash className="text-6xl text-gray-400" />
                  </div>
                  <p className="text-2xl font-semibold">{doctor?.name}</p>
                  <p className="text-gray-300 text-lg">Camera is turned off</p>
                </div>
              )}
            </div>
          ) : (
            <div className="text-white text-center">
              <div className="w-40 h-40 bg-gradient-to-br from-green-500 to-green-700 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-white shadow-2xl">
                <FaMicrophone className="text-6xl" />
              </div>
              <p className="text-2xl font-semibold mb-2">{doctor?.name}</p>
              <p className="text-gray-300 text-lg mb-4">Audio Call Active</p>
              <div className="flex items-center justify-center gap-4">
                <div className="w-12 h-12 bg-blue-500 rounded-full flex items-center justify-center">
                  <span className="text-lg font-bold">{doctor?.name?.charAt(0)}</span>
                </div>
                <div className="w-12 h-12 bg-green-500 rounded-full flex items-center justify-center">
                  <span className="text-lg font-bold">You</span>
                </div>
              </div>
            </div>
          )}
          
          {/* Chat Panel (if open) */}
          {showChat && !isMinimized && (
            <div className="absolute right-4 top-4 bottom-4 w-80 bg-white rounded-lg shadow-xl flex flex-col">
              <div className="p-4 border-b border-gray-200 flex items-center justify-between">
                <h4 className="font-semibold text-gray-900">Chat</h4>
                <button
                  onClick={() => setShowChat(false)}
                  className="text-gray-400 hover:text-gray-600"
                >
                  <FaTimes />
                </button>
              </div>
              <div className="flex-1 p-4 text-gray-600 text-center">
                <p>Chat feature coming soon...</p>
              </div>
            </div>
          )}
        </div>

        {/* Controls */}
        <div className="bg-gray-800 p-6">
          <div className="flex items-center justify-center gap-4">
            {/* Mute Toggle */}
            <button
              onClick={() => setIsMuted(!isMuted)}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-200 ${
                isMuted ? 'bg-red-600 hover:bg-red-700' : 'bg-gray-600 hover:bg-gray-700'
              }`}
              title={isMuted ? "Unmute" : "Mute"}
            >
              {isMuted ? <FaMicrophoneSlash className="text-white text-xl" /> : <FaMicrophone className="text-white text-xl" />}
            </button>

            {/* Camera Toggle (Video only) */}
            {callType === 'video' && (
              <button
                onClick={() => setIsCameraOn(!isCameraOn)}
                className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-200 ${
                  !isCameraOn ? 'bg-red-600 hover:bg-red-700' : 'bg-gray-600 hover:bg-gray-700'
                }`}
                title={isCameraOn ? "Turn off camera" : "Turn on camera"}
              >
                {isCameraOn ? <FaVideo className="text-white text-xl" /> : <FaVideoSlash className="text-white text-xl" />}
              </button>
            )}

            {/* Switch Camera (Video only) */}
            {callType === 'video' && (
              <button 
                className="w-14 h-14 rounded-full bg-gray-600 hover:bg-gray-700 flex items-center justify-center transition-all duration-200"
                title="Switch camera"
              >
                <FaVideo className="text-white text-xl transform rotate-180" />
              </button>
            )}

            {/* Speaker Toggle (Audio only) */}
            {callType === 'audio' && (
              <button
                onClick={() => setIsSpeakerOn(!isSpeakerOn)}
                className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-200 ${
                  isSpeakerOn ? 'bg-blue-600 hover:bg-blue-700' : 'bg-gray-600 hover:bg-gray-700'
                }`}
                title={isSpeakerOn ? "Turn off speaker" : "Turn on speaker"}
              >
                <FaVolumeUp className={`text-xl ${isSpeakerOn ? 'text-white' : 'text-gray-400'}`} />
              </button>
            )}

            {/* Chat Toggle */}
            <button
              onClick={() => setShowChat(!showChat)}
              className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-200 ${
                showChat ? 'bg-blue-600 hover:bg-blue-700' : 'bg-gray-600 hover:bg-gray-700'
              }`}
              title="Toggle chat"
            >
              <FaComment className="text-white text-xl" />
            </button>

            {/* End Call */}
            <button
              onClick={onEndCall}
              className="w-16 h-16 rounded-full bg-red-600 hover:bg-red-700 flex items-center justify-center transition-all duration-200 shadow-lg"
              title="End call"
            >
              <FaPhoneSlash className="text-white text-2xl" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const Home = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const [doctors, setDoctors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSpecialty, setSelectedSpecialty] = useState('');
  const [availableOnly, setAvailableOnly] = useState(false);
  const [showConsultModal, setShowConsultModal] = useState(false);
  const [showCallUI, setShowCallUI] = useState(false);
  const [callType, setCallType] = useState('');
  const [selectedDoctorForCall, setSelectedDoctorForCall] = useState(null);

  // Dummy data for demonstration
  const dummyDoctors = [
    {
      id: '1',
      name: 'Dr. Rajesh Kumar',
      specialty: 'Cardiology',
      qualifications: 'MBBS, MD Cardiology',
      experience_years: 15,
      consultation_fee: 500,
      is_available: true,
      languages: 'English, Hindi, Punjabi',
      rating: 4.8,
      total_consultations: 1200,
      profile_image: null
    },
    {
      id: '2',
      name: 'Dr. Priya Sharma',
      specialty: 'Pediatrics',
      qualifications: 'MBBS, MD Pediatrics',
      experience_years: 10,
      consultation_fee: 400,
      is_available: true,
      languages: 'English, Hindi',
      rating: 4.6,
      total_consultations: 800,
      profile_image: null
    },
    {
      id: '3',
      name: 'Dr. Harpreet Singh',
      specialty: 'General Medicine',
      qualifications: 'MBBS, MD Internal Medicine',
      experience_years: 12,
      consultation_fee: 350,
      is_available: false,
      languages: 'English, Hindi, Punjabi',
      rating: 4.5,
      total_consultations: 950,
      profile_image: null
    },
    {
      id: '4',
      name: 'Dr. Sunita Devi',
      specialty: 'Gynecology',
      qualifications: 'MBBS, MS Gynecology',
      experience_years: 8,
      consultation_fee: 450,
      is_available: true,
      languages: 'English, Hindi, Punjabi',
      rating: 4.7,
      total_consultations: 600,
      profile_image: null
    }
  ];

  useEffect(() => {
    fetchDoctors();
  }, []);

  const fetchDoctors = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll use dummy data
      // In production, uncomment the API call below
      // const response = await doctorAPI.getAll();
      // setDoctors(response.data);
      
      // Simulate API delay
      setTimeout(() => {
        setDoctors(dummyDoctors);
        setLoading(false);
      }, 1000);
    } catch (error) {
      console.error('Error fetching doctors:', error);
      setError('Failed to load doctors');
      setDoctors(dummyDoctors); // Fallback to dummy data
      setLoading(false);
    }
  };

  const filteredDoctors = doctors.filter(doctor => {
    const matchesSearch = doctor.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         doctor.specialty.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesSpecialty = !selectedSpecialty || doctor.specialty === selectedSpecialty;
    const matchesAvailability = !availableOnly || doctor.is_available;
    
    return matchesSearch && matchesSpecialty && matchesAvailability;
  });

  const specialties = [...new Set(doctors.map(doctor => doctor.specialty))];

  const renderStars = (rating) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 !== 0;
    const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

    for (let i = 0; i < fullStars; i++) {
      stars.push(<FaStar key={`full-${i}`} className="star" />);
    }
    
    if (hasHalfStar) {
      stars.push(<FaStarHalfAlt key="half" className="star" />);
    }
    
    for (let i = 0; i < emptyStars; i++) {
      stars.push(<FaRegStar key={`empty-${i}`} className="star empty" />);
    }

    return stars;
  };

  const handleConsultNow = (doctorId) => {
    const doctor = filteredDoctors.find(d => d.id === doctorId);
    setSelectedDoctorForCall(doctor);
    setCallType('video');
    setShowCallUI(true);
  };

  const handleBookAppointment = (doctorId) => {
    const doctor = filteredDoctors.find(d => d.id === doctorId);
    // Navigate to appointments page with doctor data in state
    navigate('/appointments', { 
      state: { selectedDoctor: doctor }
    });
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="loading"></div>
          <span className="ml-2">Loading doctors...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="text-center mb-12">
        <h1 className="text-4xl font-bold text-gray-900 mb-4">
          Welcome to Helio
        </h1>
        <p className="text-lg text-gray-600">
          Your Health, Our Priority - Connect with healthcare professionals instantly
        </p>
      </div>

      {/* Main Feature Buttons */}
      <div className="flex flex-col items-center gap-6 mb-12">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full max-w-4xl">
          {/* Video Call Button */}
          <button
            onClick={() => {
              setCallType('video');
              setSelectedDoctorForCall({
                name: 'Dr. Available',
                specialty: 'General Physician'
              });
              setShowCallUI(true);
            }}
            className="group relative overflow-hidden bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white rounded-2xl p-8 shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300"
          >
            <div className="flex flex-col items-center">
              <div className="bg-white bg-opacity-20 rounded-full p-4 mb-4 group-hover:bg-opacity-30 transition-all duration-300">
                <FaVideo className="text-4xl" />
              </div>
              <h3 className="text-xl font-bold mb-2">Consult by Video Call</h3>
              <p className="text-blue-100 text-sm">Face-to-face consultation with doctors</p>
            </div>
            <div className="absolute top-0 right-0 w-32 h-32 bg-white bg-opacity-10 rounded-full -mr-16 -mt-16"></div>
          </button>

          {/* Audio Call Button */}
          <button
            onClick={() => {
              setCallType('audio');
              setSelectedDoctorForCall({
                name: 'Dr. Available',
                specialty: 'General Physician'
              });
              setShowCallUI(true);
            }}
            className="group relative overflow-hidden bg-gradient-to-r from-green-600 to-green-700 hover:from-green-700 hover:to-green-800 text-white rounded-2xl p-8 shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300"
          >
            <div className="flex flex-col items-center">
              <div className="bg-white bg-opacity-20 rounded-full p-4 mb-4 group-hover:bg-opacity-30 transition-all duration-300">
                <FaMicrophone className="text-4xl" />
              </div>
              <h3 className="text-xl font-bold mb-2">Consult by Audio Call</h3>
              <p className="text-green-100 text-sm">Voice consultation with healthcare experts</p>
            </div>
            <div className="absolute top-0 right-0 w-32 h-32 bg-white bg-opacity-10 rounded-full -mr-16 -mt-16"></div>
          </button>

          {/* Book Appointment Button */}
          <button
            onClick={() => navigate('/appointments')}
            className="group relative overflow-hidden bg-gradient-to-r from-purple-600 to-purple-700 hover:from-purple-700 hover:to-purple-800 text-white rounded-2xl p-8 shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300"
          >
            <div className="flex flex-col items-center">
              <div className="bg-white bg-opacity-20 rounded-full p-4 mb-4 group-hover:bg-opacity-30 transition-all duration-300">
                <FaCalendar className="text-4xl" />
              </div>
              <h3 className="text-xl font-bold mb-2">Book Appointment</h3>
              <p className="text-purple-100 text-sm">Schedule a visit with your preferred doctor</p>
            </div>
            <div className="absolute top-0 right-0 w-32 h-32 bg-white bg-opacity-10 rounded-full -mr-16 -mt-16"></div>
          </button>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-lg shadow-md border p-6 mb-8 max-w-4xl mx-auto">
        <h2 className="text-xl font-semibold text-gray-900 mb-4 text-center">Find Available Doctors</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 items-center">
          {/* Search */}
          <div className="relative">
            <FaSearch className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder={`${t('search')} ${t('doctors').toLowerCase()}...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="input pl-12 w-full"
            />
          </div>

          {/* Specialty Filter */}
          <div className="relative">
            <FaFilter className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <select
              value={selectedSpecialty}
              onChange={(e) => setSelectedSpecialty(e.target.value)}
              className="input pl-12 w-full"
            >
              <option value="">All Specialties</option>
              {specialties.map(specialty => (
                <option key={specialty} value={specialty}>{specialty}</option>
              ))}
            </select>
          </div>

          {/* Availability Filter */}
          <div className="flex items-center justify-center gap-3">
            <input
              type="checkbox"
              id="availableOnly"
              checked={availableOnly}
              onChange={(e) => setAvailableOnly(e.target.checked)}
              className="rounded border-gray-300 text-primary-color focus:ring-primary-color"
            />
            <label htmlFor="availableOnly" className="text-sm font-medium text-gray-700">
              {t('available')} only
            </label>
          </div>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-100 border border-red-300 text-red-700 p-4 rounded-lg mb-6 max-w-4xl mx-auto">
          {error}
        </div>
      )}

      {/* Doctors Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {filteredDoctors.map((doctor) => (
          <div key={doctor.id} className="card hover:shadow-xl transition-all duration-300 flex flex-col h-full">
            {/* Doctor Header */}
            <div className="flex-grow">
              <div className="flex items-center gap-4 mb-4">
                <div className="w-20 h-20 bg-gradient-to-br from-blue-500 to-blue-700 rounded-full flex items-center justify-center text-white text-3xl font-bold">
                  {doctor.profile_image ? (
                    <img 
                      src={doctor.profile_image} 
                      alt={doctor.name}
                      className="w-full h-full rounded-full object-cover"
                    />
                  ) : (
                    <FaUserMd />
                  )}
                </div>
                
                <div className="flex-1 text-left">
                  <h3 className="font-bold text-xl text-gray-900">{doctor.name}</h3>
                  <p className="text-blue-600 font-semibold">{doctor.specialty}</p>
                </div>
              </div>

              {/* Doctor Info */}
              <div className="space-y-3 mb-6 text-left">
                <p className="text-gray-700">{doctor.qualifications}</p>
                <div className="flex items-center justify-between text-sm">
                  <div className="flex items-center gap-2">
                    <FaClock className="text-gray-500" />
                    <span className="text-gray-700">
                      {doctor.experience_years} years exp.
                    </span>
                  </div>
                  <div className="flex items-center gap-1">
                    <div className="rating flex items-center text-yellow-500">
                      {renderStars(doctor.rating)}
                    </div>
                    <span className="text-gray-600 ml-1">
                      ({doctor.total_consultations})
                    </span>
                  </div>
                </div>

                <div className="flex items-center gap-2 text-sm">
                  <FaLanguage className="text-gray-500" />
                  <span className="text-gray-700">{doctor.languages}</span>
                </div>
              </div>
            </div>

            {/* Action Buttons */}
            <div className="mt-auto pt-4 border-t border-gray-200">
              <div className="grid grid-cols-2 gap-3">
                <button
                  onClick={() => handleConsultNow(doctor.id)}
                  disabled={!doctor.is_available}
                  className="btn btn-primary flex items-center justify-center gap-2 w-full"
                >
                  <FaVideo />
                  {t('consult_now')}
                </button>
                
                <button
                  onClick={() => handleBookAppointment(doctor.id)}
                  className="btn btn-outline flex items-center justify-center gap-2 w-full"
                >
                  <FaCalendar />
                  {t('book_appointment')}
                </button>
              </div>
              <div className={`mt-2 text-center text-sm font-medium ${
                  doctor.is_available 
                    ? 'text-green-600' 
                    : 'text-red-600'
                }`}>
                  {doctor.is_available ? t('available') : t('unavailable')}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* No Results */}
      {filteredDoctors.length === 0 && !loading && (
        <div className="text-center py-12">
          <FaUserMd className="mx-auto text-6xl text-gray-300 mb-4" />
          <h3 className="text-xl font-medium text-gray-900 mb-2">No doctors found</h3>
          <p className="text-gray-600">
            Try adjusting your search criteria or filters
          </p>
        </div>
      )}

      {/* Call UI Modal */}
      {showCallUI && <CallUI callType={callType} doctor={selectedDoctorForCall} onEndCall={() => {
        setShowCallUI(false);
        setCallType('');
        setSelectedDoctorForCall(null);
      }} />}
    </div>
  );
};

export default Home;
